30: 
31: /**
32:  * This class ties together all the components of a Kafka Connect process (herder, worker,
33:  * storage, command interface), managing their lifecycle.
34:  */
35: public class Connect<H extends Herder> {
36:     private static final Logger log = LoggerFactory.getLogger(Connect.class);
37: 
38:     private final H herder;
39:     private Future<?> herderTask;
40:     private final ConnectRestServer rest;
41:     private final CountDownLatch startLatch = new CountDownLatch(1);
42:     private final CountDownLatch stopLatch = new CountDownLatch(1);
43:     private final AtomicBoolean shutdown = new AtomicBoolean(false);
44:     private final ShutdownHook shutdownHook;
45: 
46:     public Connect(H herder, ConnectRestServer rest) {
47:         log.debug("Kafka Connect instance created");
48:         this.herder = herder;
49:         this.rest = rest;
50:         shutdownHook = new ShutdownHook();
51:     }
52: 
53:     /**
54:      * Track task status which have been submitted to work thread.
55:      * @return {@link DistributedHerder#herderTask} to track status or null if the herder type doesn't have a separate work thread
56:      */
57:     public Future<?> herderTask() {
58:         return this.herderTask;
59:     }
60: 
61:     public H herder() {
62:         return herder;
63:     }
64: 
