72: /**
73:  * Embedded server for the REST API that provides the control plane for Kafka Connect workers.
74:  */
75: public abstract class RestServer {
76: 
77:     // TODO: This should not be so long. However, due to potentially long rebalances that may have to wait a full
78:     // session timeout to complete, during which we cannot serve some requests. Ideally we could reduce this, but
79:     // we need to consider all possible scenarios this could fail. It might be ok to fail with a timeout in rare cases,
80:     // but currently a worker simply leaving the group can take this long as well.
81:     public static final long DEFAULT_REST_REQUEST_TIMEOUT_MS = TimeUnit.SECONDS.toMillis(90);
82:     public static final long DEFAULT_HEALTH_CHECK_TIMEOUT_MS = TimeUnit.SECONDS.toMillis(10);
83: 
84:     private static final Logger log = LoggerFactory.getLogger(RestServer.class);
85: 
86:     // Used to distinguish between Admin connectors and regular REST API connectors when binding admin handlers
87:     private static final String ADMIN_SERVER_CONNECTOR_NAME = "Admin";
88: 
89:     private static final Pattern LISTENER_PATTERN = Pattern.compile("^(.*)://\\[?([0-9a-zA-Z\\-%._:]*)\\]?:(-?[0-9]+)");
90:     private static final long GRACEFUL_SHUTDOWN_TIMEOUT_MS = 60 * 1000;
91: 
92:     private static final String PROTOCOL_HTTP = "http";
93:     private static final String PROTOCOL_HTTPS = "https";
94: 
95:     protected final RestServerConfig config;
96:     private final ContextHandlerCollection handlers;
97:     private final Server jettyServer;
98:     private final RequestTimeout requestTimeout;
99: 
100:     private List<Plugin<ConnectRestExtension>> connectRestExtensionPlugins = Collections.emptyList();
101: 
102:     /**
103:      * Create a REST server for this herder using the specified configs.
104:      */
105:     protected RestServer(RestServerConfig config) {
106:         this.config = config;
107: 
108:         List<String> listeners = config.listeners();
109:         List<String> adminListeners = config.adminListeners();
110: 
111:         jettyServer = new Server();
112:         handlers = new ContextHandlerCollection();
113:         requestTimeout = new RequestTimeout(DEFAULT_REST_REQUEST_TIMEOUT_MS, DEFAULT_HEALTH_CHECK_TIMEOUT_MS);
114: 
115:         createConnectors(listeners, adminListeners);
116:     }
117: 
118:     /**
119:      * Adds Jetty connector for each configured listener
120:      */
121:     public final void createConnectors(List<String> listeners, List<String> adminListeners) {
122:         List<Connector> connectors = new ArrayList<>();
123: 
124:         for (String listener : listeners) {
125:             Connector connector = createConnector(listener);
126:             connectors.add(connector);
127:             log.info("Added connector for {}", listener);
128:         }
129: 
130:         jettyServer.setConnectors(connectors.toArray(new Connector[0]));
131: 
132:         if (adminListeners != null && !adminListeners.isEmpty()) {
133:             for (String adminListener : adminListeners) {
134:                 Connector conn = createConnector(adminListener, true);
135:                 jettyServer.addConnector(conn);
136:                 log.info("Added admin connector for {}", adminListener);
137:             }
138:         }
139:     }
140: 
141:     /**
142:      * Creates regular (non-admin) Jetty connector according to configuration
143:      */
144:     public final Connector createConnector(String listener) {
145:         return createConnector(listener, false);
146:     }
147: 
148:     /**
149:      * Creates Jetty connector according to configuration
150:      */
151:     public final Connector createConnector(String listener, boolean isAdmin) {
152:         Matcher listenerMatcher = LISTENER_PATTERN.matcher(listener);
153: 
154:         if (!listenerMatcher.matches())
155:             throw new ConfigException("Listener doesn't have the right format (protocol://hostname:port).");
156: 
157:         String protocol = listenerMatcher.group(1).toLowerCase(Locale.ENGLISH);
158: 
159:         if (!PROTOCOL_HTTP.equals(protocol) && !PROTOCOL_HTTPS.equals(protocol))
160:             throw new ConfigException(String.format("Listener protocol must be either \"%s\" or \"%s\".", PROTOCOL_HTTP, PROTOCOL_HTTPS));
161: 
162:         String hostname = listenerMatcher.group(2);
163:         int port = Integer.parseInt(listenerMatcher.group(3));
164: 
165:         ServerConnector connector;
166: 
167:         if (PROTOCOL_HTTPS.equals(protocol)) {
168:             SslContextFactory.Server ssl;
169:             if (isAdmin) {
170:                 ssl = SSLUtils.createServerSideSslContextFactory(config, RestServerConfig.ADMIN_LISTENERS_HTTPS_CONFIGS_PREFIX);
171:             } else {
172:                 ssl = SSLUtils.createServerSideSslContextFactory(config);
173:             }
174:             connector = new ServerConnector(jettyServer, ssl);
175:             if (!isAdmin) {
176:                 connector.setName(String.format("%s_%s%d", PROTOCOL_HTTPS, hostname, port));
177:             }
178:         } else {
179:             connector = new ServerConnector(jettyServer);
180:             if (!isAdmin) {
181:                 connector.setName(String.format("%s_%s%d", PROTOCOL_HTTP, hostname, port));
182:             }
183:         }
184: 
185:         if (isAdmin) {
186:             connector.setName(ADMIN_SERVER_CONNECTOR_NAME);
187:         }
188: 
189:         if (!hostname.isEmpty())
190:             connector.setHost(hostname);
191: 
192:         connector.setPort(port);
193: 
194:         // TODO: do we need this?
195:         connector.setIdleTimeout(requestTimeout.timeoutMs());
196: 
197:         return connector;
198:     }
199: 
200:     public void initializeServer() {
201:         log.info("Initializing REST server");
202: 
203:         Slf4jRequestLogWriter slf4jRequestLogWriter = new Slf4jRequestLogWriter();
204:         slf4jRequestLogWriter.setLoggerName(RestServer.class.getCanonicalName());
205:         CustomRequestLog requestLog = new CustomRequestLog(slf4jRequestLogWriter, CustomRequestLog.EXTENDED_NCSA_FORMAT + " %{ms}T");
206:         jettyServer.setRequestLog(requestLog);
207: 
208:         /* Needed for graceful shutdown as per `setStopTimeout` documentation */
209:         StatisticsHandler statsHandler = new StatisticsHandler();
210:         statsHandler.setHandler(handlers);
211:         jettyServer.setHandler(statsHandler);
212:         jettyServer.setStopTimeout(GRACEFUL_SHUTDOWN_TIMEOUT_MS);
213:         jettyServer.setStopAtShutdown(true);
214: 
215:         try {
216:             jettyServer.start();
217:         } catch (Exception e) {
218:             throw new ConnectException("Unable to initialize REST server", e);
219:         }
220: 
221:         log.info("REST server listening at {}, advertising URL {}", jettyServer.getURI(), advertisedUrl());
222:         URI adminUrl = adminUrl();
223:         if (adminUrl != null)
224:             log.info("REST admin endpoints at {}", adminUrl);
225:     }
226: 
227:     protected final void initializeResources() {
228:         log.info("Initializing REST resources");
229: 
230:         ResourceConfig resourceConfig = newResourceConfig();
231:         Collection<Class<?>> regularResources = regularResources();
232:         regularResources.forEach(resourceConfig::register);
233:         configureRegularResources(resourceConfig);
234: 
235:         List<String> adminListeners = config.adminListeners();
236:         ResourceConfig adminResourceConfig;
237:         if (adminListeners != null && adminListeners.isEmpty()) {
238:             log.info("Skipping adding admin resources");
239:             // set up adminResource but add no handlers to it
240:             adminResourceConfig = resourceConfig;
241:         } else {
242:             if (adminListeners == null) {
243:                 log.info("Adding admin resources to main listener");
244:                 adminResourceConfig = resourceConfig;
245:             } else {
246:                 // TODO: we need to check if these listeners are same as 'listeners'
247:                 // TODO: the following code assumes that they are different
248:                 log.info("Adding admin resources to admin listener");
249:                 adminResourceConfig = newResourceConfig();
250:             }
251:             Collection<Class<?>> adminResources = adminResources();
252:             adminResources.forEach(adminResourceConfig::register);
253:             configureAdminResources(adminResourceConfig);
254:         }
255: 
256:         ServletContainer servletContainer = new ServletContainer(resourceConfig);
257:         ServletHolder servletHolder = new ServletHolder(servletContainer);
258:         List<Handler> contextHandlers = new ArrayList<>();
259: 
260:         ServletContextHandler context = new ServletContextHandler(ServletContextHandler.SESSIONS);
261:         context.setContextPath("/");
262:         context.addServlet(servletHolder, "/*");
263:         contextHandlers.add(context);
264: 
265:         ServletContextHandler adminContext = null;
266:         if (adminResourceConfig != resourceConfig) {
267:             adminContext = new ServletContextHandler(ServletContextHandler.SESSIONS);
268:             ServletHolder adminServletHolder = new ServletHolder(new ServletContainer(adminResourceConfig));
269:             adminContext.setContextPath("/");
270:             adminContext.addServlet(adminServletHolder, "/*");
271:             adminContext.setVirtualHosts(List.of("@" + ADMIN_SERVER_CONNECTOR_NAME));
272:             contextHandlers.add(adminContext);
273:         }
274: 
275:         String allowedOrigins = config.allowedOrigins();
276:         if (!Utils.isBlank(allowedOrigins)) {
277:             CrossOriginHandler crossOriginHandler = new CrossOriginHandler();
278:             crossOriginHandler.setAllowedOriginPatterns(Set.of(allowedOrigins.split(",")));
279:             String allowedMethods = config.allowedMethods();
280:             if (!Utils.isBlank(allowedMethods)) {
281:                 crossOriginHandler.setAllowedMethods(Set.of(allowedMethods.split(",")));
282:             }
283:             // Setting to true matches the previously used CrossOriginFilter
284:             crossOriginHandler.setDeliverPreflightRequests(true);
285:             context.insertHandler(crossOriginHandler);
286:         }
287: 
288:         String headerConfig = config.responseHeaders();
289:         if (!Utils.isBlank(headerConfig)) {
290:             configureHttpResponseHeaderFilter(context, headerConfig);
291:         }
292: 
293:         handlers.setHandlers(contextHandlers.toArray(new Handler[0]));
294:         try {
295:             context.start();
296:         } catch (Exception e) {
297:             throw new ConnectException("Unable to initialize REST resources", e);
298:         }
299: 
300:         if (adminResourceConfig != resourceConfig) {
301:             try {
302:                 log.debug("Starting admin context");
303:                 adminContext.start();
304:             } catch (Exception e) {
305:                 throw new ConnectException("Unable to initialize Admin REST resources", e);
306:             }
307:         }
308: 
309:         log.info("REST resources initialized; server is started and ready to handle requests");
310:     }
311: 
312:     private ResourceConfig newResourceConfig() {
313:         ResourceConfig result = new ResourceConfig();
314:         result.register(new JacksonJsonProvider());
315:         result.register(requestTimeout.binder());
316:         result.register(ConnectExceptionMapper.class);
317:         result.property(ServerProperties.WADL_FEATURE_DISABLE, true);
318:         return result;
319:     }
320: 
321:     /**
322:      * @return the resources that should be registered with the
323:      * standard (i.e., non-admin) listener for this server; may be empty, but not null
324:      */
325:     protected abstract Collection<Class<?>> regularResources();
326: 
327:     /**
328:      * @return the resources that should be registered with the
329:      * admin listener for this server; may be empty, but not null
330:      */
331:     protected abstract Collection<Class<?>> adminResources();
332: 
333:     /**
334:      * Pluggable hook to customize the regular (i.e., non-admin) resources on this server
335:      * after they have been instantiated and registered with the given {@link ResourceConfig}.
336:      * This may be used to, for example, add REST extensions via {@link #registerRestExtensions(Herder, ResourceConfig)}.
337:      * <p>
338:      * <em>N.B.: Classes do <b>not</b> need to register the resources provided in {@link #regularResources()} with
339:      * the {@link ResourceConfig} parameter in this method; they are automatically registered by the parent class.</em>
340:      * @param resourceConfig the {@link ResourceConfig} that the server's regular listeners are registered with; never null
341:      */
342:     protected void configureRegularResources(ResourceConfig resourceConfig) {
343:         // No-op by default
344:     }
345: 
346:     /**
347:      * Pluggable hook to customize the admin resources on this server after they have been instantiated and registered
348:      * with the given {@link ResourceConfig}. This may be used to, for example, add REST extensions via
349:      * {@link #registerRestExtensions(Herder, ResourceConfig)}.
350:      * <p>
351:      * <em>N.B.: Classes do <b>not</b> need to register the resources provided in {@link #adminResources()} with
352:      * the {@link ResourceConfig} parameter in this method; they are automatically registered by the parent class.</em>
353:      * @param adminResourceConfig the {@link ResourceConfig} that the server's admin listeners are registered with; never null
354:      */
355:     protected void configureAdminResources(ResourceConfig adminResourceConfig) {
356:         // No-op by default
357:     }
358: 
359:     public URI serverUrl() {
360:         return jettyServer.getURI();
361:     }
362: 
363:     public void stop() {
364:         log.info("Stopping REST server");
365: 
366:         try {
367:             if (handlers.isRunning()) {
368:                 for (Handler handler : handlers.getHandlers()) {
369:                     if (handler != null) {
370:                         Utils.closeQuietly(handler::stop, handler.toString());
371:                     }
372:                 }
373:             }
374:             for (Plugin<ConnectRestExtension> connectRestExtensionPlugin : connectRestExtensionPlugins) {
375:                 try {
376:                     connectRestExtensionPlugin.close();
377:                 } catch (IOException e) {
378:                     log.warn("Error while invoking close on {}", connectRestExtensionPlugin.get().getClass(), e);
379:                 }
380:             }
381:             jettyServer.stop();
382:             jettyServer.join();
383:         } catch (Exception e) {
384:             throw new ConnectException("Unable to stop REST server", e);
385:         } finally {
386:             try {
387:                 jettyServer.destroy();
388:             } catch (Exception e) {
389:                 log.error("Unable to destroy REST server", e);
390:             }
391:         }
392: 
393:         log.info("REST server stopped");
394:     }
395: 
396:     /**
397:      * Get the URL to advertise to other workers and clients. This uses the default connector from the embedded Jetty
398:      * server, unless overrides for advertised hostname and/or port are provided via configs. {@link #initializeServer()}
399:      * must be invoked successfully before calling this method.
400:      */
401:     public URI advertisedUrl() {
402:         UriBuilder builder = UriBuilder.fromUri(jettyServer.getURI());
403: 
404:         String advertisedSecurityProtocol = determineAdvertisedProtocol();
405:         ServerConnector serverConnector = findConnector(advertisedSecurityProtocol);
406:         builder.scheme(advertisedSecurityProtocol);
407: 
408:         String advertisedHostname = config.advertisedHostName();
409:         if (advertisedHostname != null && !advertisedHostname.isEmpty())
410:             builder.host(advertisedHostname);
411:         else if (serverConnector != null && serverConnector.getHost() != null && !serverConnector.getHost().isEmpty())
412:             builder.host(serverConnector.getHost());
413: 
414:         Integer advertisedPort = config.advertisedPort();
415:         if (advertisedPort != null)
416:             builder.port(advertisedPort);
417:         else if (serverConnector != null && serverConnector.getPort() > 0)
418:             builder.port(serverConnector.getPort());
419:         else if (serverConnector != null && serverConnector.getLocalPort() > 0)
420:             builder.port(serverConnector.getLocalPort());
421: 
422:         log.info("Advertised URI: {}", builder.build());
423: 
424:         return builder.build();
425:     }
426: 
427:     /**
428:      * @return the admin url for this worker. Can be null if admin endpoints are disabled.
429:      */
430:     public URI adminUrl() {
431:         ServerConnector adminConnector = null;
432:         for (Connector connector : jettyServer.getConnectors()) {
433:             if (ADMIN_SERVER_CONNECTOR_NAME.equals(connector.getName()))
434:                 adminConnector = (ServerConnector) connector;
435:         }
436: 
437:         if (adminConnector == null) {
438:             List<String> adminListeners = config.adminListeners();
439:             if (adminListeners == null) {
440:                 return advertisedUrl();
441:             } else if (adminListeners.isEmpty()) {
442:                 return null;
443:             } else {
444:                 log.error("No admin connector found for listeners {}", adminListeners);
445:                 return null;
446:             }
447:         }
448: 
449:         UriBuilder builder = UriBuilder.fromUri(jettyServer.getURI());
450:         builder.port(adminConnector.getLocalPort());
451: 
452:         return builder.build();
453:     }
