507:     protected final void registerRestExtensions(Herder herder, ResourceConfig resourceConfig) {
508:         connectRestExtensionPlugins = Plugin.wrapInstances(
509:                 herder.plugins().newPlugins(
510:                     config.restExtensions(),
511:                     config,
512:                     ConnectRestExtension.class
513:                 ),
514:                 herder.connectMetrics().metrics(),
515:                 RestServerConfig.REST_EXTENSION_CLASSES_CONFIG);
516: 
517:         long herderRequestTimeoutMs = DEFAULT_REST_REQUEST_TIMEOUT_MS;
518: 
519:         Integer rebalanceTimeoutMs = config.rebalanceTimeoutMs();
520: 
521:         if (rebalanceTimeoutMs != null) {
522:             herderRequestTimeoutMs = Math.min(herderRequestTimeoutMs, rebalanceTimeoutMs.longValue());
523:         }
524: 
525:         ConnectClusterDetails connectClusterDetails = new ConnectClusterDetailsImpl(
526:             herder.kafkaClusterId()
527:         );
528: 
529:         ConnectRestExtensionContext connectRestExtensionContext =
530:             new ConnectRestExtensionContextImpl(
531:                 new ConnectRestConfigurable(resourceConfig),
532:                 new ConnectClusterStateImpl(herderRequestTimeoutMs, connectClusterDetails, herder)
533:             );
534:         for (Plugin<ConnectRestExtension> connectRestExtensionPlugin : connectRestExtensionPlugins) {
535:             connectRestExtensionPlugin.get().register(connectRestExtensionContext);
536:         }
537: 
538:     }
