550:     private static class RequestTimeout implements RestRequestTimeout {
551: 
552:         private final RequestBinder binder;
553:         private volatile long timeoutMs;
554:         private volatile long healthCheckTimeoutMs;
555: 
556:         public RequestTimeout(long initialTimeoutMs, long initialHealthCheckTimeoutMs) {
557:             this.timeoutMs = initialTimeoutMs;
558:             this.healthCheckTimeoutMs = initialHealthCheckTimeoutMs;
559:             this.binder = new RequestBinder();
560:         }
561: 
562:         @Override
563:         public long timeoutMs() {
564:             return timeoutMs;
565:         }
566: 
567:         @Override
568:         public long healthCheckTimeoutMs() {
569:             return healthCheckTimeoutMs;
570:         }
571: 
572:         public void timeoutMs(long timeoutMs) {
573:             this.timeoutMs = timeoutMs;
574:         }
575: 
576:         public void healthCheckTimeoutMs(long healthCheckTimeoutMs) {
577:             this.healthCheckTimeoutMs = healthCheckTimeoutMs;
578:         }
579: 
580:         public Binder binder() {
581:             return binder;
582:         }
583: 
584:         private class RequestBinder extends AbstractBinder {
585:             @Override
586:             protected void configure() {
587:                 bind(RequestTimeout.this).to(RestRequestTimeout.class);
588:             }
589:         }
590:     }
591: }
