59: /**
60:  * <p>
61:  *     Implementation of OffsetBackingStore that uses a Kafka topic to store offset data.
62:  * </p>
63:  * <p>
64:  *     Internally, this implementation both produces to and consumes from a Kafka topic which stores the offsets.
65:  *     It accepts producer and consumer overrides via its configuration but forces some settings to specific values
66:  *     to ensure correct behavior (e.g. acks, auto.offset.reset).
67:  * </p>
68:  */
69: public class KafkaOffsetBackingStore extends KafkaTopicBasedBackingStore implements OffsetBackingStore {
70:     private static final Logger log = LoggerFactory.getLogger(KafkaOffsetBackingStore.class);
71: 
72:     /**
73:      * Build a connector-specific offset store with read and write support. The producer will be {@link Producer#close(Duration) closed}
74:      * and the consumer will be {@link Consumer#close(Duration) closed} when this store is {@link #stop() stopped}, but the topic admin
75:      * must be {@link TopicAdmin#close(Duration) closed} by the caller.
76:      * @param topic the name of the offsets topic to use
77:      * @param producer the producer to use for writing to the offsets topic
78:      * @param consumer the consumer to use for reading from the offsets topic
79:      * @param topicAdmin the topic admin to use for creating and querying metadata for the offsets topic
80:      * @param keyConverter the worker's internal key converter that can be used to deserialize offset keys from the {@link KafkaBasedLog}
81:      * @return an offset store backed by the given topic and Kafka clients
82:      */
83:     public static KafkaOffsetBackingStore readWriteStore(
84:             String topic,
85:             Producer<byte[], byte[]> producer,
86:             Consumer<byte[], byte[]> consumer,
87:             TopicAdmin topicAdmin,
88:             Converter keyConverter
89:     ) {
90:         return new KafkaOffsetBackingStore(() -> topicAdmin, KafkaOffsetBackingStore::noClientId, keyConverter) {
91:             @Override
92:             public void configure(final WorkerConfig config) {
93:                 this.exactlyOnce = config.exactlyOnceSourceEnabled();
94:                 this.offsetLog = KafkaBasedLog.withExistingClients(
95:                         topic,
96:                         consumer,
97:                         producer,
98:                         topicAdmin,
99:                         consumedCallback,
100:                         Time.SYSTEM,
101:                         topicInitializer(topic, newTopicDescription(topic, config), config, Time.SYSTEM),
102:                         ignored -> true
103:                 );
104:             }
105:         };
106:     }
107: 
108:     /**
109:      * Build a connector-specific offset store with read-only support. The consumer will be {@link Consumer#close(Duration) closed}
110:      * when this store is {@link #stop() stopped}, but the topic admin must be {@link TopicAdmin#close(Duration) closed} by the caller.
111:      * @param topic the name of the offsets topic to use
112:      * @param consumer the consumer to use for reading from the offsets topic
113:      * @param topicAdmin the topic admin to use for creating and querying metadata for the offsets topic
114:      * @param keyConverter the worker's internal key converter that can be used to deserialize offset keys from the {@link KafkaBasedLog}
115:      * @return a read-only offset store backed by the given topic and Kafka clients
116:      */
117:     public static KafkaOffsetBackingStore readOnlyStore(
118:             String topic,
119:             Consumer<byte[], byte[]> consumer,
120:             TopicAdmin topicAdmin,
121:             Converter keyConverter
122:     ) {
123:         return new KafkaOffsetBackingStore(() -> topicAdmin, KafkaOffsetBackingStore::noClientId, keyConverter) {
124:             @Override
125:             public void configure(final WorkerConfig config) {
126:                 this.exactlyOnce = config.exactlyOnceSourceEnabled();
127:                 this.offsetLog = KafkaBasedLog.withExistingClients(
128:                         topic,
129:                         consumer,
130:                         null,
131:                         topicAdmin,
132:                         consumedCallback,
133:                         Time.SYSTEM,
134:                         topicInitializer(topic, newTopicDescription(topic, config), config, Time.SYSTEM),
135:                         ignored -> true
136:                 );
137:             }
138:         };
139:     }
140: 
141:     private static String noClientId() {
142:         throw new UnsupportedOperationException("This offset store should not instantiate any Kafka clients");
143:     }
144: 
145:     protected KafkaBasedLog<byte[], byte[]> offsetLog;
146:     // Visible for testing
147:     final HashMap<ByteBuffer, ByteBuffer> data = new HashMap<>();
148:     private final Map<String, Set<Map<String, Object>>> connectorPartitions = new HashMap<>();
149:     private Converter keyConverter;
150:     private final Supplier<TopicAdmin> topicAdminSupplier;
151:     private final Supplier<String> clientIdBase;
152:     protected boolean exactlyOnce;
153: 
154:     /**
155:      * Create an {@link OffsetBackingStore} backed by a Kafka topic. This constructor will use the given
156:      * {@link Supplier} to acquire a {@link TopicAdmin} that will be used for interactions with the backing
157:      * Kafka topic. The caller is expected to manage the lifecycle of that object, including
158:      * {@link TopicAdmin#close(Duration) closing} it when it is no longer needed.
159:      * @param topicAdmin a {@link Supplier} for the {@link TopicAdmin} to use for this backing store;
160:      *                   may not be null, and may not return null
161:      * @param clientIdBase a {@link Supplier} that will be used to create a
162:      * {@link CommonClientConfigs#CLIENT_ID_DOC client ID} for Kafka clients instantiated by this store;
163:      *                     may not be null, and may not return null, but may throw {@link UnsupportedOperationException}
164:      *                     if this offset store should not create its own Kafka clients
165:      */
166:     public KafkaOffsetBackingStore(Supplier<TopicAdmin> topicAdmin, Supplier<String> clientIdBase, Converter keyConverter) {
167:         this.topicAdminSupplier = Objects.requireNonNull(topicAdmin);
168:         this.clientIdBase = Objects.requireNonNull(clientIdBase);
169:         this.keyConverter = keyConverter;
170:     }
171: 
172:     @Override
173:     public void configure(final WorkerConfig config) {
174:         String topic = config.getString(DistributedConfig.OFFSET_STORAGE_TOPIC_CONFIG);
175:         if (topic == null || topic.trim().isEmpty())
176:             throw new ConfigException("Offset storage topic must be specified");
177: 
178:         this.exactlyOnce = config.exactlyOnceSourceEnabled();
179: 
180:         String clusterId = config.kafkaClusterId();
181:         String clientId = Objects.requireNonNull(clientIdBase.get()) + "offsets";
182: 
183:         Map<String, Object> originals = config.originals();
184:         Map<String, Object> producerProps = new HashMap<>(originals);
185:         producerProps.put(ProducerConfig.KEY_SERIALIZER_CLASS_CONFIG, ByteArraySerializer.class.getName());
186:         producerProps.put(ProducerConfig.VALUE_SERIALIZER_CLASS_CONFIG, ByteArraySerializer.class.getName());
187:         producerProps.put(ProducerConfig.DELIVERY_TIMEOUT_MS_CONFIG, Integer.MAX_VALUE);
188:         // By default, Connect disables idempotent behavior for all producers, even though idempotence became
189:         // default for Kafka producers. This is to ensure Connect continues to work with many Kafka broker versions, including older brokers that do not support
190:         // idempotent producers or require explicit steps to enable them (e.g. adding the IDEMPOTENT_WRITE ACL to brokers older than 2.8).
191:         // These settings might change when https://cwiki.apache.org/confluence/display/KAFKA/KIP-318%3A+Make+Kafka+Connect+Source+idempotent
192:         // gets approved and scheduled for release.
193:         producerProps.put(ProducerConfig.ENABLE_IDEMPOTENCE_CONFIG, "false");
194:         producerProps.put(CommonClientConfigs.CLIENT_ID_CONFIG, clientId);
195:         ConnectUtils.addMetricsContextProperties(producerProps, config, clusterId);
196: 
197:         Map<String, Object> consumerProps = new HashMap<>(originals);
198:         consumerProps.put(ConsumerConfig.KEY_DESERIALIZER_CLASS_CONFIG, ByteArrayDeserializer.class.getName());
199:         consumerProps.put(ConsumerConfig.VALUE_DESERIALIZER_CLASS_CONFIG, ByteArrayDeserializer.class.getName());
200:         consumerProps.put(CommonClientConfigs.CLIENT_ID_CONFIG, clientId);
201:         ConnectUtils.addMetricsContextProperties(consumerProps, config, clusterId);
202:         if (config.exactlyOnceSourceEnabled()) {
203:             ConnectUtils.ensureProperty(
204:                     consumerProps, ConsumerConfig.ISOLATION_LEVEL_CONFIG, IsolationLevel.READ_COMMITTED.toString(),
205:                     "for the worker offsets topic consumer when exactly-once source support is enabled",
206:                     false
207:             );
208:         }
209: 
210:         Map<String, Object> adminProps = new HashMap<>(originals);
211:         adminProps.put(CommonClientConfigs.CLIENT_ID_CONFIG, clientId);
212:         ConnectUtils.addMetricsContextProperties(adminProps, config, clusterId);
213:         NewTopic topicDescription = newTopicDescription(topic, config);
214: 
215:         this.offsetLog = createKafkaBasedLog(topic, producerProps, consumerProps, consumedCallback, topicDescription, topicAdminSupplier, config, Time.SYSTEM);
216:     }
217: 
218:     protected NewTopic newTopicDescription(final String topic, final WorkerConfig config) {
219:         Map<String, Object> topicSettings = config instanceof DistributedConfig
220:                 ? ((DistributedConfig) config).offsetStorageTopicSettings()
221:                 : Collections.emptyMap();
222:         return TopicAdmin.defineTopic(topic)
223:                 .config(topicSettings) // first so that we override user-supplied settings as needed
224:                 .compacted()
225:                 .partitions(config.getInt(DistributedConfig.OFFSET_STORAGE_PARTITIONS_CONFIG))
226:                 .replicationFactor(config.getShort(DistributedConfig.OFFSET_STORAGE_REPLICATION_FACTOR_CONFIG))
227:                 .build();
228:     }
229: 
230:     @Override
231:     public void start() {
232:         log.info("Starting KafkaOffsetBackingStore");
233:         try {
234:             offsetLog.start();
235:         } catch (UnsupportedVersionException e) {
236:             String message;
237:             if (exactlyOnce) {
238:                 message = "Enabling exactly-once support for source connectors requires a Kafka broker version that allows "
239:                         + "admin clients to read consumer offsets. Please either disable the worker's exactly-once "
240:                         + "support for source connectors, or upgrade to a newer Kafka broker version.";
241:             } else {
242:                 message = "When " + ConsumerConfig.ISOLATION_LEVEL_CONFIG + "is set to "
243:                         + IsolationLevel.READ_COMMITTED
244:                         + ", a Kafka broker version that allows admin clients to read consumer offsets is required. "
245:                         + "Please either reconfigure the worker or connector, or upgrade to a newer Kafka broker version.";
246:             }
247:             throw new ConnectException(message, e);
248:         }
249:         log.info("Finished reading offsets topic and starting KafkaOffsetBackingStore");
250:     }
