410:     // public for testing
411:     public void tick() {
412:         // The main loop does two primary things: 1) drive the group membership protocol, responding to rebalance events
413:         // as they occur, and 2) handle external requests targeted at the leader. All the "real" work of the herder is
414:         // performed in this thread, which keeps synchronization straightforward at the cost of some operations possibly
415:         // blocking up this thread (especially those in callbacks due to rebalance events).
416: 
417:         try {
418:             // if we failed to read to end of log before, we need to make sure the issue was resolved before joining group
419:             // Joining and immediately leaving for failure to read configs is exceedingly impolite
420:             if (!canReadConfigs) {
421:                 if (readConfigToEnd(workerSyncTimeoutMs)) {
422:                     canReadConfigs = true;
423:                 } else {
424:                     return; // Safe to return and tick immediately because readConfigToEnd will do the backoff for us
425:                 }
426:             }
427: 
428:             log.debug("Ensuring group membership is still active");
429:             String stageDescription = "ensuring membership in the cluster";
430:             member.ensureActive(() -> new TickThreadStage(stageDescription));
431:             completeTickThreadStage();
432:             // Ensure we're in a good state in our group. If not restart and everything should be setup to rejoin
433:             if (!handleRebalanceCompleted()) return;
434:         } catch (WakeupException e) {
435:             // May be due to a request from another thread, or might be stopping. If the latter, we need to check the
436:             // flag immediately. If the former, we need to re-run the ensureActive call since we can't handle requests
437:             // unless we're in the group.
438:             log.trace("Woken up while ensure group membership is still active");
439:             return;
440:         }
441: 
442:         if (fencedFromConfigTopic) {
443:             if (isLeader()) {
444:                 // We were accidentally fenced out, possibly by a zombie leader
445:                 try {
446:                     log.debug("Reclaiming write privileges for config topic after being fenced out");
447:                     try (TickThreadStage stage = new TickThreadStage("reclaiming write privileges for the config topic")) {
448:                         configBackingStore.claimWritePrivileges();
449:                     }
450:                     fencedFromConfigTopic = false;
451:                     log.debug("Successfully reclaimed write privileges for config topic after being fenced out");
452:                 } catch (Exception e) {
453:                     log.warn("Unable to claim write privileges for config topic. Will backoff and possibly retry if still the leader", e);
454:                     backoff(CONFIG_TOPIC_WRITE_PRIVILEGES_BACKOFF_MS);
455:                     return;
456:                 }
457:             } else {
458:                 log.trace("Relinquished write privileges for config topic after being fenced out, since worker is no longer the leader of the cluster");
459:                 // We were meant to be fenced out because we fell out of the group and a new leader was elected
460:                 fencedFromConfigTopic = false;
461:             }
462:         }
463: 
464:         long now = time.milliseconds();
465: 
466:         if (checkForKeyRotation(now)) {
467:             log.debug("Distributing new session key");
468:             keyExpiration = Long.MAX_VALUE;
469:             try {
470:                 SessionKey newSessionKey = new SessionKey(keyGenerator.generateKey(), now);
471:                 writeToConfigTopicAsLeader(
472:                         "writing a new session key to the config topic",
473:                         () -> configBackingStore.putSessionKey(newSessionKey)
474:                 );
475:             } catch (Exception e) {
476:                 log.info("Failed to write new session key to config topic; forcing a read to the end of the config topic before possibly retrying", e);
477:                 canReadConfigs = false;
478:                 return;
479:             }
480:         }
481: 
482:         // Process any external requests
483:         // TODO: Some of these can be performed concurrently or even optimized away entirely.
484:         //       For example, if three different connectors are slated to be restarted, it's fine to
485:         //       restart all three at the same time instead.
486:         //       Another example: if multiple configurations are submitted for the same connector,
487:         //       the only one that actually has to be written to the config topic is the
488:         //       most-recently one.
489:         Long scheduledTick = null;
490:         while (true) {
491:             final DistributedHerderRequest next = peekWithoutException();
492:             if (next == null) {
493:                 break;
494:             } else if (now >= next.at) {
495:                 currentRequest = requests.pollFirst();
496:             } else {
497:                 scheduledTick = next.at;
498:                 break;
499:             }
500: 
501:             runRequest(next.action(), next.callback());
502:         }
503: 
504:         // Process all pending connector restart requests
505:         processRestartRequests();
506: 
507:         if (scheduledRebalance < Long.MAX_VALUE) {
508:             scheduledTick = scheduledTick != null ? Math.min(scheduledTick, scheduledRebalance) : scheduledRebalance;
509:             rebalanceResolved = false;
510:             log.debug("Scheduled rebalance at: {} (now: {} scheduledTick: {}) ",
511:                     scheduledRebalance, now, scheduledTick);
512:         }
513:         if (isLeader() && internalRequestValidationEnabled() && keyExpiration < Long.MAX_VALUE) {
514:             scheduledTick = scheduledTick != null ? Math.min(scheduledTick, keyExpiration) : keyExpiration;
515:             log.debug("Scheduled next key rotation at: {} (now: {} scheduledTick: {}) ",
516:                     keyExpiration, now, scheduledTick);
517:         }
518: 
519:         // Process any configuration updates
520:         AtomicReference<Set<String>> connectorConfigUpdatesCopy = new AtomicReference<>();
521:         AtomicReference<Set<String>> connectorTargetStateChangesCopy = new AtomicReference<>();
522:         AtomicReference<Set<ConnectorTaskId>> taskConfigUpdatesCopy = new AtomicReference<>();
523: 
524:         boolean shouldReturn;
525:         if (member.currentProtocolVersion() == CONNECT_PROTOCOL_V0) {
526:             shouldReturn = updateConfigsWithEager(connectorConfigUpdatesCopy,
527:                     connectorTargetStateChangesCopy);
528:             // With eager protocol we should return immediately if needsReconfigRebalance has
529:             // been set to retain the old workflow
530:             if (shouldReturn) {
531:                 return;
532:             }
533: 
534:             if (connectorConfigUpdatesCopy.get() != null) {
535:                 processConnectorConfigUpdates(connectorConfigUpdatesCopy.get());
536:             }
537: 
538:             if (connectorTargetStateChangesCopy.get() != null) {
539:                 processTargetStateChanges(connectorTargetStateChangesCopy.get());
540:             }
541:         } else {
542:             shouldReturn = updateConfigsWithIncrementalCooperative(connectorConfigUpdatesCopy,
543:                     connectorTargetStateChangesCopy, taskConfigUpdatesCopy);
544: 
545:             if (connectorConfigUpdatesCopy.get() != null) {
546:                 processConnectorConfigUpdates(connectorConfigUpdatesCopy.get());
547:             }
548: 
549:             if (connectorTargetStateChangesCopy.get() != null) {
550:                 processTargetStateChanges(connectorTargetStateChangesCopy.get());
551:             }
552: 
553:             if (taskConfigUpdatesCopy.get() != null) {
554:                 processTaskConfigUpdatesWithIncrementalCooperative(taskConfigUpdatesCopy.get());
555:             }
556: 
557:             if (shouldReturn) {
558:                 return;
559:             }
560:         }
561: 
562:         // Let the group take any actions it needs to
563:         try {
564:             long nextRequestTimeoutMs = scheduledTick != null ? Math.max(scheduledTick - time.milliseconds(), 0L) : Long.MAX_VALUE;
565:             log.trace("Polling for group activity; will wait for {}ms or until poll is interrupted by "
566:                     + "either config backing store updates or a new external request",
567:                     nextRequestTimeoutMs);
568:             String pollDurationDescription = scheduledTick != null ? "for up to " + nextRequestTimeoutMs + "ms or " : "";
569:             String stageDescription = "polling the group coordinator " + pollDurationDescription + "until interrupted";
570:             member.poll(nextRequestTimeoutMs, () -> new TickThreadStage(stageDescription));
571:             completeTickThreadStage();
572:             // Ensure we're in a good state in our group. If not restart and everything should be setup to rejoin
573:             handleRebalanceCompleted();
574:         } catch (WakeupException e) { // FIXME should not be WakeupException
575:             log.trace("Woken up while polling for group activity");
576:             // Ignore. Just indicates we need to check the exit flag, for requested actions, etc.
577:         }
578:     }
