580:     private boolean checkForKeyRotation(long now) {
581:         SecretKey key;
582:         long expiration;
583:         synchronized (this) {
584:             // This happens on startup; the snapshot contains the session key,
585:             // but no callback in the config update listener has been fired for it yet.
586:             if (sessionKey == null && configState.sessionKey() != null) {
587:                 sessionKey = configState.sessionKey().key();
588:                 keyExpiration = configState.sessionKey().creationTimestamp() + keyRotationIntervalMs;
589:             }
590:             key = sessionKey;
591:             expiration = keyExpiration;
592:         }
593: 
594:         if (internalRequestValidationEnabled()) {
595:             if (isLeader()) {
596:                 if (key == null) {
597:                     log.debug("Internal request signing is enabled but no session key has been distributed yet. "
598:                         + "Distributing new key now.");
599:                     return true;
600:                 } else if (expiration <= now) {
601:                     log.debug("Existing key has expired. Distributing new key now.");
602:                     return true;
603:                 } else if (!key.getAlgorithm().equals(keyGenerator.getAlgorithm())
604:                         || key.getEncoded().length != keyGenerator.generateKey().getEncoded().length) {
605:                     log.debug("Previously-distributed key uses different algorithm/key size "
606:                         + "than required by current worker configuration. Distributing new key now.");
607:                     return true;
608:                 }
609:             }
610:         }
611:         return false;
612:     }
