614:     private synchronized boolean updateConfigsWithEager(AtomicReference<Set<String>> connectorConfigUpdatesCopy,
615:                                                         AtomicReference<Set<String>> connectorTargetStateChangesCopy) {
616:         // This branch is here to avoid creating a snapshot if not needed
617:         if (needsReconfigRebalance
618:                 || !connectorConfigUpdates.isEmpty()
619:                 || !connectorTargetStateChanges.isEmpty()) {
620:             log.trace("Handling config updates with eager rebalancing");
621:             // Connector reconfigs only need local updates since there is no coordination between workers required.
622:             // However, if connectors were added or removed, work needs to be rebalanced since we have more work
623:             // items to distribute among workers.
624:             configState = configBackingStore.snapshot();
625: 
626:             if (needsReconfigRebalance) {
627:                 // Task reconfigs require a rebalance. Request the rebalance, clean out state, and then restart
628:                 // this loop, which will then ensure the rebalance occurs without any other requests being
629:                 // processed until it completes.
630:                 log.debug("Requesting rebalance due to reconfiguration of tasks (needsReconfigRebalance: {})",
631:                         needsReconfigRebalance);
632:                 member.requestRejoin();
633:                 needsReconfigRebalance = false;
634:                 // Any connector config updates or target state changes will be addressed during the rebalance too
635:                 connectorConfigUpdates.clear();
636:                 connectorTargetStateChanges.clear();
637:                 return true;
638:             } else {
639:                 if (!connectorConfigUpdates.isEmpty()) {
640:                     // We can't start/stop while locked since starting connectors can cause task updates that will
641:                     // require writing configs, which in turn make callbacks into this class from another thread that
642:                     // require acquiring a lock. This leads to deadlock. Instead, just copy the info we need and process
643:                     // the updates after unlocking.
644:                     connectorConfigUpdatesCopy.set(connectorConfigUpdates);
645:                     connectorConfigUpdates = new HashSet<>();
646:                 }
647: 
648:                 if (!connectorTargetStateChanges.isEmpty()) {
649:                     // Similarly for target state changes which can cause connectors to be restarted
650:                     connectorTargetStateChangesCopy.set(connectorTargetStateChanges);
651:                     connectorTargetStateChanges = new HashSet<>();
652:                 }
653:             }
654:         } else {
655:             log.trace("Skipping config updates with eager rebalancing "
656:                 + "since no config rebalance is required "
657:                 + "and there are no connector config, task config, or target state changes pending");
658:         }
659:         return false;
660:     }
