662:     private synchronized boolean updateConfigsWithIncrementalCooperative(AtomicReference<Set<String>> connectorConfigUpdatesCopy,
663:                                                                          AtomicReference<Set<String>> connectorTargetStateChangesCopy,
664:                                                                          AtomicReference<Set<ConnectorTaskId>> taskConfigUpdatesCopy) {
665:         boolean retValue = false;
666:         // This branch is here to avoid creating a snapshot if not needed
667:         if (needsReconfigRebalance
668:                 || !connectorConfigUpdates.isEmpty()
669:                 || !connectorTargetStateChanges.isEmpty()
670:                 || !taskConfigUpdates.isEmpty()) {
671:             log.trace("Handling config updates with incremental cooperative rebalancing");
672:             // Connector reconfigs only need local updates since there is no coordination between workers required.
673:             // However, if connectors were added or removed, work needs to be rebalanced since we have more work
674:             // items to distribute among workers.
675:             configState = configBackingStore.snapshot();
676: 
677:             if (needsReconfigRebalance) {
678:                 log.debug("Requesting rebalance due to reconfiguration of tasks (needsReconfigRebalance: {})",
679:                         needsReconfigRebalance);
680:                 member.requestRejoin();
681:                 needsReconfigRebalance = false;
682:                 retValue = true;
683:             }
684: 
685:             if (!connectorConfigUpdates.isEmpty()) {
686:                 // We can't start/stop while locked since starting connectors can cause task updates that will
687:                 // require writing configs, which in turn make callbacks into this class from another thread that
688:                 // require acquiring a lock. This leads to deadlock. Instead, just copy the info we need and process
689:                 // the updates after unlocking.
690:                 connectorConfigUpdatesCopy.set(connectorConfigUpdates);
691:                 connectorConfigUpdates = new HashSet<>();
692:             }
693: 
694:             if (!connectorTargetStateChanges.isEmpty()) {
695:                 // Similarly for target state changes which can cause connectors to be restarted
696:                 connectorTargetStateChangesCopy.set(connectorTargetStateChanges);
697:                 connectorTargetStateChanges = new HashSet<>();
698:             }
699: 
700:             if (!taskConfigUpdates.isEmpty()) {
701:                 // Similarly for task config updates
702:                 taskConfigUpdatesCopy.set(taskConfigUpdates);
703:                 taskConfigUpdates = new HashSet<>();
704:             }
705:         } else {
706:             log.trace("Skipping config updates with incremental cooperative rebalancing " 
707:                 + "since no config rebalance is required " 
708:                 + "and there are no connector config, task config, or target state changes pending");
709:         }
710:         return retValue;
711:     }
