713:     private void processConnectorConfigUpdates(Set<String> connectorConfigUpdates) {
714:         // If we only have connector config updates, we can just bounce the updated connectors that are
715:         // currently assigned to this worker.
716:         Set<String> localConnectors = assignment == null ? Collections.emptySet() : new HashSet<>(assignment.connectors());
717:         Collection<Callable<Void>> connectorsToStart = new ArrayList<>();
718:         log.trace("Processing connector config updates; "
719:                 + "currently-owned connectors are {}, and to-be-updated connectors are {}",
720:                 localConnectors,
721:                 connectorConfigUpdates);
722:         for (String connectorName : connectorConfigUpdates) {
723:             if (!localConnectors.contains(connectorName)) {
724:                 log.trace("Skipping config update for connector {} as it is not owned by this worker",
725:                         connectorName);
726:                 continue;
727:             }
728:             boolean remains = configState.contains(connectorName);
729:             log.info("Handling connector-only config update by {} connector {}",
730:                     remains ? "restarting" : "stopping", connectorName);
731:             try (TickThreadStage stage = new TickThreadStage("stopping connector " + connectorName)) {
732:                 worker.stopAndAwaitConnector(connectorName);
733:             }
734:             // The update may be a deletion, so verify we actually need to restart the connector
735:             if (remains) {
736:                 connectorsToStart.add(getConnectorStartingCallable(connectorName));
737:             }
738:         }
739:         String stageDescription = "restarting " + connectorsToStart.size() + " reconfigured connectors";
740:         startAndStop(connectorsToStart, stageDescription);
741:     }
