743:     private void processTargetStateChanges(Set<String> connectorTargetStateChanges) {
744:         log.trace("Processing target state updates; "
745:                 + "currently-known connectors are {}, and to-be-updated connectors are {}",
746:                 configState.connectors(), connectorTargetStateChanges);
747:         for (String connector : connectorTargetStateChanges) {
748:             TargetState targetState = configState.targetState(connector);
749:             if (!configState.connectors().contains(connector)) {
750:                 log.debug("Received target state change for unknown connector: {}", connector);
751:                 continue;
752:             }
753: 
754:             // we must propagate the state change to the worker so that the connector's
755:             // tasks can transition to the new target state
756:             worker.setTargetState(connector, targetState, (error, newState) -> {
757:                 if (error != null) {
758:                     log.error("Failed to transition connector to target state", error);
759:                     return;
760:                 }
761:                 // additionally, if the worker is running the connector itself, then we need to
762:                 // request reconfiguration to ensure that config changes while paused take effect
763:                 if (newState == TargetState.STARTED) {
764:                     requestTaskReconfiguration(connector);
765:                 }
766:             });
767:         }
768:     }
