770:     private void processTaskConfigUpdatesWithIncrementalCooperative(Set<ConnectorTaskId> taskConfigUpdates) {
771:         Set<ConnectorTaskId> localTasks = assignment == null
772:                                           ? Collections.emptySet()
773:                                           : new HashSet<>(assignment.tasks());
774:         log.trace("Processing task config updates with incremental cooperative rebalance protocol; "
775:                 + "currently-owned tasks are {}, and to-be-updated tasks are {}",
776:                 localTasks, taskConfigUpdates);
777:         Set<String> connectorsWhoseTasksToStop = taskConfigUpdates.stream()
778:                 .map(ConnectorTaskId::connector).collect(Collectors.toSet());
779:         stopReconfiguredTasks(connectorsWhoseTasksToStop);
780:     }
781: 
782:     private void stopReconfiguredTasks(Set<String> connectors) {
783:         Set<ConnectorTaskId> localTasks = assignment == null
784:                 ? Collections.emptySet()
785:                 : new HashSet<>(assignment.tasks());
786: 
787:         List<ConnectorTaskId> tasksToStop = localTasks.stream()
788:                 .filter(taskId -> connectors.contains(taskId.connector()))
789:                 .collect(Collectors.toList());
790: 
791:         if (tasksToStop.isEmpty()) {
792:             // The rest of the method would essentially be a no-op so this isn't strictly necessary,
793:             // but it prevents an unnecessary log message from being emitted
794:             return;
795:         }
796: 
797:         log.info("Handling task config update by stopping tasks {}, which will be restarted after rebalance if still assigned to this worker", tasksToStop);
798:         try (TickThreadStage stage = new TickThreadStage("stopping " + tasksToStop.size() + " reconfigured tasks")) {
799:             worker.stopAndAwaitTasks(tasksToStop);
800:         }
801:         tasksToRestart.addAll(tasksToStop);
802:     }
