153:                           StatusBackingStore statusBackingStore,
154:                           ConfigBackingStore configBackingStore,
155:                           ConnectorClientConfigOverridePolicy connectorClientConfigOverridePolicy,
156:                           Time time) {
157:         this.worker = worker;
158:         this.worker.herder = this;
159:         this.workerId = workerId;
160:         this.kafkaClusterId = kafkaClusterId;
161:         this.statusBackingStore = statusBackingStore;
162:         this.configBackingStore = configBackingStore;
163:         this.connectorClientConfigOverridePolicyPlugin = Plugin.wrapInstance(
164:                 connectorClientConfigOverridePolicy,
165:                 worker.metrics().metrics(),
166:                 WorkerConfig.CONNECTOR_CLIENT_POLICY_CLASS_CONFIG);
167:         this.connectorExecutor = Executors.newCachedThreadPool();
168:         this.time = time;
169:         this.loggers = Loggers.newInstance(time);
170:         this.cachedConnectors = new CachedConnectors(worker.getPlugins());
171:     }
